import sys

class Solution:

def findMaximum(self, nums: list[int]) -> int:
	if not nums:
		return -1
	max_val = nums[0]
	for num in nums[1:]:
		if num > max_val:
			max_val = num
	return max_val

def main():
	nums = list(map(int, input().split()))
	print(Solution().findMaximum(nums))
if __name__ == '__main__':
	main()
